-- Albert Einstein (1–22)
(gen_random_uuid(), 'El tiempo es relativo: depende de dónde estés y a qué velocidad te muevas respecto a otro observador.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La relatividad nos enseña que el espacio y el tiempo son una sola tela que la materia curva a su alrededor.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La energía y la masa son dos caras de la misma moneda; esa equivalencia cambió nuestra visión del universo.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
