(gen_random_uuid(), 'La contracción de la longitud a velocidades relativistas es tan real como cualquier otro fenómeno físico.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
