(gen_random_uuid(), 'Las ondas gravitacionales son riples en el tejido del espacio-tiempo, predichas antes de ser detectadas.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La física teórica es el arte de construir modelos matemáticos que describen la realidad con elegancia.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'learning', 'wisdom'], true, 'science'),
